import React, { useState, useContext } from 'react';
import { FaTrash, FaThumbsUp, FaRegThumbsUp } from 'react-icons/fa';
import { toast } from 'react-toastify';
import { AuthContext } from '../context/AuthContext';
import forumService from '../services/forumService';
import { formatDistanceToNow } from 'date-fns';

const CommentItem = ({ comment, postId, onDeleteComment }) => {
  const { user } = useContext(AuthContext);
  const [liked, setLiked] = useState(comment.likes?.includes(user?._id));
  const [likeCount, setLikeCount] = useState(comment.likes?.length || 0);
  const [isDeleting, setIsDeleting] = useState(false);

  const handleLike = async () => {
    if (!user) {
      toast.error('Please log in to like comments');
      return;
    }

    try {
      const response = await forumService.likeComment(postId, comment._id);
      setLiked(!liked);
      setLikeCount(liked ? likeCount - 1 : likeCount + 1);
    } catch (error) {
      toast.error('Failed to like comment');
      console.error(error);
    }
  };

  const handleDelete = async () => {
    if (!user || (user._id !== comment.user._id && !user.isAdmin)) {
      toast.error('You are not authorized to delete this comment');
      return;
    }

    try {
      setIsDeleting(true);
      await forumService.deleteComment(postId, comment._id);
      onDeleteComment(comment._id);
      toast.success('Comment deleted successfully');
    } catch (error) {
      toast.error('Failed to delete comment');
      console.error(error);
    } finally {
      setIsDeleting(false);
    }
  };

  return (
    <div className="border-b dark:border-gray-700 py-4">
      <div className="flex justify-between items-start mb-2">
        <div className="flex items-center">
          <div className="h-8 w-8 rounded-full bg-green-500 flex items-center justify-center text-white font-semibold mr-2">
            {comment.user.name.charAt(0).toUpperCase()}
          </div>
          <div>
            <h4 className="font-medium text-gray-900 dark:text-white">{comment.user.name}</h4>
            <p className="text-xs text-gray-500 dark:text-gray-400">
              {formatDistanceToNow(new Date(comment.createdAt), { addSuffix: true })}
            </p>
          </div>
        </div>
        
        {user && (user._id === comment.user._id || user.isAdmin) && (
          <button 
            onClick={handleDelete} 
            disabled={isDeleting}
            className="text-red-500 hover:text-red-700 dark:hover:text-red-400 disabled:opacity-50"
          >
            <FaTrash size={14} />
          </button>
        )}
      </div>
      
      <p className="text-gray-700 dark:text-gray-300 mb-3">{comment.text}</p>
      
      <div className="flex items-center">
        <button 
          onClick={handleLike} 
          className="flex items-center text-gray-600 dark:text-gray-400 hover:text-blue-600 dark:hover:text-blue-400"
        >
          {liked ? (
            <FaThumbsUp className="text-blue-600 dark:text-blue-400 mr-1" size={14} />
          ) : (
            <FaRegThumbsUp className="mr-1" size={14} />
          )}
          <span className="text-sm">{likeCount}</span>
        </button>
      </div>
    </div>
  );
};

export default CommentItem;
